import{_ as e,c as o,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Recursos Avançados: Multi-Agente e Desenvolvimento de Habilidades | OpenSkills","description":"Aprenda recursos avançados do OpenSkills, incluindo configuração de ambiente multi-agente, desenvolvimento de habilidades personalizadas, integração CI/CD e mecanismos de segurança para gerenciar cenários complexos com eficiência.","frontmatter":{"title":"Recursos Avançados: Multi-Agente e Desenvolvimento de Habilidades | OpenSkills","sidebarTitle":"Multi-Contas e Habilidades Personalizadas","subtitle":"Recursos Avançados: Multi-Agente e Desenvolvimento de Habilidades","description":"Aprenda recursos avançados do OpenSkills, incluindo configuração de ambiente multi-agente, desenvolvimento de habilidades personalizadas, integração CI/CD e mecanismos de segurança para gerenciar cenários complexos com eficiência.","order":3},"headers":[],"relativePath":"pt/numman-ali/openskills/advanced/index.md","filePath":"pt/numman-ali/openskills/advanced/index.md"}'),s={name:"pt/numman-ali/openskills/advanced/index.md"};function d(r,a,n,l,c,u){return i(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="recursos-avancados" tabindex="-1">Recursos Avançados <a class="header-anchor" href="#recursos-avancados" aria-label="Permalink to &quot;Recursos Avançados&quot;">​</a></h1><p>Este capítulo aborda usos avançados do OpenSkills, incluindo configuração de ambiente multi-agente, saídas personalizadas, desenvolvimento com links simbólicos, criação de habilidades, integração CI/CD e mecanismos de segurança. Após dominar este conteúdo, você poderá gerenciar habilidades com eficiência em cenários complexos e criar sua própria biblioteca de habilidades.</p><div class="warning custom-block"><p class="custom-block-title">Pré-requisitos</p><p>Antes de aprender este capítulo, certifique-se de ter concluído:</p><ul><li><a href="./../start/quick-start/">Início Rápido</a>: Compreender processos básicos de instalação e uso</li><li><a href="./../start/first-skill/">Instalar Primeira Habilidade</a>: Dominar métodos de instalação de habilidades</li><li><a href="./../start/sync-to-agents/">Sincronizar Habilidades para AGENTS.md</a>: Entender mecanismos de sincronização de habilidades</li></ul></div><h2 id="conteudo-do-capitulo" tabindex="-1">Conteúdo do Capítulo <a class="header-anchor" href="#conteudo-do-capitulo" aria-label="Permalink to &quot;Conteúdo do Capítulo&quot;">​</a></h2><h3 id="multi-agente-e-configuracao-de-saida" tabindex="-1">Multi-Agente e Configuração de Saída <a class="header-anchor" href="#multi-agente-e-configuracao-de-saida" aria-label="Permalink to &quot;Multi-Agente e Configuração de Saída&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descrição</th></tr></thead><tbody><tr><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td></tr></tbody></table><h3 id="desenvolvimento-de-habilidades" tabindex="-1">Desenvolvimento de Habilidades <a class="header-anchor" href="#desenvolvimento-de-habilidades" aria-label="Permalink to &quot;Desenvolvimento de Habilidades&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descrição</th></tr></thead><tbody><tr><td><a href="./symlink-support/">Suporte a Links Simbólicos</a></td><td>Atualizações baseadas em git e fluxo de trabalho de desenvolvimento local através de links simbólicos, compartilhamento de habilidades entre múltiplos projetos</td></tr><tr><td><a href="./create-skills/">Criar Habilidades Personalizadas</a></td><td>Criar arquivos de habilidade SKILL.md do zero, dominando especificações YAML frontmatter e estrutura de diretórios</td></tr><tr><td><a href="./skill-structure/">Estrutura de Habilidades em Detalhes</a></td><td>Compreensão aprofundada das especificações completas do SKILL.md, design de recursos references/scripts/assets/ e otimização de desempenho</td></tr></tbody></table><h3 id="automacao-e-seguranca" tabindex="-1">Automação e Segurança <a class="header-anchor" href="#automacao-e-seguranca" aria-label="Permalink to &quot;Automação e Segurança&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descrição</th></tr></thead><tbody><tr><td>---</td><td>---</td></tr><tr><td><a href="./security/">Notas de Segurança</a></td><td>Compreender três camadas de mecanismos de proteção: prevenção de path traversal, processamento seguro de links simbólicos, análise segura de YAML</td></tr></tbody></table><h3 id="guias-compreensivos" tabindex="-1">Guias Compreensivos <a class="header-anchor" href="#guias-compreensivos" aria-label="Permalink to &quot;Guias Compreensivos&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tutorial</th><th>Descrição</th></tr></thead><tbody><tr><td><a href="./best-practices/">Melhores Práticas</a></td><td>Resumo de experiências em configuração de projetos, gerenciamento de habilidades e colaboração em equipe, ajudando você a usar o OpenSkills de forma eficiente</td></tr></tbody></table><h2 id="recomendacoes-de-rota-de-aprendizado" tabindex="-1">Recomendações de Rota de Aprendizado <a class="header-anchor" href="#recomendacoes-de-rota-de-aprendizado" aria-label="Permalink to &quot;Recomendações de Rota de Aprendizado&quot;">​</a></h2><p>Escolha a rota de aprendizado apropriada com base no seu cenário de uso:</p><h3 id="rota-a-usuario-multi-agente" tabindex="-1">Rota A: Usuário Multi-Agente <a class="header-anchor" href="#rota-a-usuario-multi-agente" aria-label="Permalink to &quot;Rota A: Usuário Multi-Agente&quot;">​</a></h3><p>Se você usa simultaneamente múltiplas ferramentas de codificação IA (Claude Code + Cursor + Windsurf, etc.):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Modo Universal → Caminho de Saída Personalizado → Melhores Práticas</span></span></code></pre></div><h3 id="rota-b-criador-de-habilidades" tabindex="-1">Rota B: Criador de Habilidades <a class="header-anchor" href="#rota-b-criador-de-habilidades" aria-label="Permalink to &quot;Rota B: Criador de Habilidades&quot;">​</a></h3><p>Se você deseja criar suas próprias habilidades e compartilhá-las com a equipe:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Criar Habilidades Personalizadas → Estrutura de Habilidades em Detalhes → Suporte a Links Simbólicos → Melhores Práticas</span></span></code></pre></div><h3 id="rota-c-devops-automacao" tabindex="-1">Rota C: DevOps/Automação <a class="header-anchor" href="#rota-c-devops-automacao" aria-label="Permalink to &quot;Rota C: DevOps/Automação&quot;">​</a></h3><p>Se você precisa integrar o OpenSkills em processos de CI/CD:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Integração CI/CD → Notas de Segurança → Melhores Práticas</span></span></code></pre></div><h3 id="rota-d-aprendizado-completo" tabindex="-1">Rota D: Aprendizado Completo <a class="header-anchor" href="#rota-d-aprendizado-completo" aria-label="Permalink to &quot;Rota D: Aprendizado Completo&quot;">​</a></h3><p>Se você deseja dominar completamente todos os recursos avançados, aprenda na seguinte ordem:</p><ol><li><a href="./universal-mode/">Modo Universal</a> - Fundamentos de ambiente multi-agente</li><li><a href="./custom-output-path/">Caminho de Saída Personalizado</a> - Configuração flexível de saída</li><li><a href="./symlink-support/">Suporte a Links Simbólicos</a> - Fluxo de trabalho de desenvolvimento eficiente</li><li><a href="./create-skills/">Criar Habilidades Personalizadas</a> - Introdução à criação de habilidades</li><li><a href="./skill-structure/">Estrutura de Habilidades em Detalhes</a> - Compreensão aprofundada do formato de habilidades</li><li><a href="./ci-integration/">Integração CI/CD</a> - Implantação automatizada</li><li><a href="./security/">Notas de Segurança</a> - Detalhes de mecanismos de segurança</li><li><a href="./best-practices/">Melhores Práticas</a> - Resumo de experiências</li></ol><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após concluir este capítulo, você pode:</p><ul><li>Consultar <a href="./../faq/faq/">Perguntas Frequentes</a> para resolver problemas encontrados durante o uso</li><li>Consultar <a href="./../appendix/cli-api/">Referência da API CLI</a> para entender a interface de linha de comando completa</li><li>Ler <a href="./../appendix/agents-md-format/">Especificação de Formato AGENTS.md</a> para compreender profundamente o formato dos arquivos gerados</li><li>Verificar <a href="./../changelog/changelog/">Registro de Alterações</a> para conhecer os recursos e alterações mais recentes</li></ul>',29)])])}const h=e(s,[["render",d]]);export{m as __pageData,h as default};
